import json, os, sys, time, math, requests
from datetime import datetime, timezone

def load_connector_config():
    try:
        with open('/run/connector.json','r') as f:
            return json.load(f)
    except Exception:
        return {'auth':{}, 'configuration':{}}

def parse_time(s):
    if not isinstance(s,str):
        return None
    for fmt in ('%Y-%m-%dT%H:%M:%S.%f%z','%Y-%m-%dT%H:%M:%S%z','%Y-%m-%dT%H:%M:%S.%fZ','%Y-%m-%dT%H:%M:%SZ'):
        try:
            if fmt.endswith('Z'):
                # Handle Zulu by replacing Z with +0000 for %z unsupported
                return datetime.strptime(s.replace('Z', '+0000'), fmt.replace('Z', '%z'))
            return datetime.strptime(s, fmt)
        except Exception:
            pass
    return None

def build_jql(project_key, window_minutes, extra_clause):
    clauses = [f'project = "{project_key}"', 'assignee IS NOT EMPTY', 'assignee CHANGED', f'updated >= -{window_minutes}m']
    if extra_clause:
        clauses.append(f'({extra_clause})')
    return ' AND '.join(clauses)

def match_assignee(issue, specific, field):
    if not specific:
        return False
    a = (issue.get('fields') or {}).get('assignee')
    if not a:
        return False
    val = None
    if field == 'accountId':
        val = a.get('accountId')
    elif field == 'emailAddress':
        val = a.get('emailAddress')
    elif field == 'displayName':
        val = a.get('displayName')
    elif field == 'name':
        val = a.get('name')
    return val == specific

def normalize_fields(fields_mode):
    if not fields_mode:
        return None
    if isinstance(fields_mode, list):
        return fields_mode
    if isinstance(fields_mode, str):
        s = fields_mode.strip()
        if ',' in s:
            vals = [p.strip() for p in s.split(',') if p.strip()]
            return vals if vals else None
        return [s]
    return None

def _coerce_search_response(data):
    issues = []
    is_last = True
    next_token = None
    if isinstance(data, dict):
        issues = data.get('issues', []) or []
        is_last = bool(data.get('isLast', True))
        next_token = data.get('nextPageToken')
    return {'issues': issues, 'isLast': is_last, 'nextPageToken': next_token}

def fetch_issues(session, base_url, jql, fields_mode, next_page_token, max_results):
    base = base_url.rstrip('/')
    nf = normalize_fields(fields_mode)
    headers_json = {'Accept': 'application/json', 'Content-Type': 'application/json'}

    url_new = base + '/rest/api/3/search/jql'
    payload_new = {'jql': jql, 'maxResults': max_results}
    if nf:
        payload_new['fields'] = nf
    if next_page_token:
        payload_new['nextPageToken'] = next_page_token

    while True:
        try:
            r = session.post(url_new, json=payload_new, headers=headers_json)
        except Exception as e:
            raise Exception(f'Jira search request failed: {e}')
        if r.status_code == 429:
            retry_after = 1
            try:
                ra = r.headers.get('Retry-After')
                if ra:
                    retry_after = int(ra)
            except Exception:
                retry_after = 1
            time.sleep(max(1, retry_after))
            continue
        if r.status_code == 200:
            return _coerce_search_response(r.json())
        else:
            raise Exception(f'Jira search failed {r.status_code}: {r.text}')

def main():
    cfg_doc = load_connector_config()
    auth = cfg_doc.get('auth',{})
    conf = cfg_doc.get('configuration',{})
    email = auth.get('jiraEmail') or os.getenv('AUTH_JIRAEMAIL')
    token = auth.get('jiraApiToken') or os.getenv('AUTH_JIRAAPITOKEN')
    if not email or not token:
        print(json.dumps({'error':'Missing Jira credentials (jiraEmail and jiraApiToken)'}))
        return
    site = conf.get('siteUrl') or os.getenv('CONFIG_SITEURL')
    project = conf.get('projectKey') or os.getenv('CONFIG_PROJECTKEY')
    if not site or not project:
        print(json.dumps({'error':'Missing configuration siteUrl or projectKey'}))
        return
    specific = conf.get('specificAssignee') if 'specificAssignee' in conf else os.getenv('CONFIG_SPECIFICASSIGNEE')
    field = (conf.get('assigneeMatchField') or os.getenv('CONFIG_ASSIGNEEMATCHFIELD') or 'accountId')
    try:
        poll = int(conf.get('pollIntervalSeconds') if 'pollIntervalSeconds' in conf else os.getenv('CONFIG_POLLINTERVALSECONDS','15'))
    except Exception:
        poll = 15
    try:
        maxr = int(conf.get('maxResultsPerPoll') if 'maxResultsPerPoll' in conf else os.getenv('CONFIG_MAXRESULTSPERPOLL','50'))
    except Exception:
        maxr = 50
    fields_mode = conf.get('fieldsMode') or os.getenv('CONFIG_FIELDSMODE') or '*all'
    extra = conf.get('jqlExtra') or os.getenv('CONFIG_JQLEXTRA')
    window_minutes = max(1, int(math.ceil((poll if poll>0 else 15)/60.0)*2))
    session = requests.Session()
    session.auth = (email, token)
    t0 = datetime.now(timezone.utc)
    seen_ids = set()
    matched = False
    collected = []
    try:
        while True:
            jql = build_jql(project, window_minutes, extra)
            next_page_token = None
            issues_this_poll = []
            while True:
                data = fetch_issues(session, site, jql, fields_mode, next_page_token, maxr)
                issues = data.get('issues',[])
                issues_this_poll.extend(issues)
                is_last = data.get('isLast', True)
                next_page_token = data.get('nextPageToken')
                if is_last or not next_page_token:
                    break
            new_issues = []
            for it in issues_this_poll:
                key = it.get('key')
                if key in seen_ids:
                    continue
                upd = (it.get('fields') or {}).get('updated')
                dt = parse_time(upd)
                if dt is None or dt >= t0:
                    new_issues.append(it)
                    seen_ids.add(key)
            if new_issues:
                collected.extend(new_issues)
                if specific:
                    for it in new_issues:
                        if match_assignee(it, specific, field):
                            matched = True
                            break
                break
            time.sleep(max(1, int(poll if poll>0 else 15)))
        out = {'projectKey': project, 'siteUrl': site, 'count': len(collected), 'matchedSpecificAssignee': matched, 'issues': collected}
        print(json.dumps(out))
    except Exception as e:
        print(json.dumps({'error': str(e)}))

if __name__ == '__main__':
    main()
